// Takes \p Foo and apply a simple constant propagation optimization.
// \returns true if \p Foo was modified (i.e., something had been constant
// propagated), false otherwise.
bool myConstantPropagation(Function &Foo) {
  if (Foo.empty())
    return false;

  bool Changed = false;
  SmallVector<Instruction *, 16> ToErase;

  ReversePostOrderTraversal<Function *> RPOT(&Foo);
  for (BasicBlock *BB : RPOT) {
    for (Instruction &I : *BB) {
      auto *BinOp = dyn_cast<BinaryOperator>(&I);
      if (!BinOp)
        continue;

      auto *LHS = dyn_cast<ConstantInt>(BinOp->getOperand(0));
      auto *RHS = dyn_cast<ConstantInt>(BinOp->getOperand(1));
      if (!LHS || !RHS)
        continue;

      const APInt &LHSVal = LHS->getValue();
      const APInt &RHSVal = RHS->getValue();
      std::optional<APInt> Result;

      switch (BinOp->getOpcode()) {
      case Instruction::Add:
        Result = LHSVal + RHSVal;
        break;
      case Instruction::Sub:
        Result = LHSVal - RHSVal;
        break;
      case Instruction::Mul:
        Result = LHSVal * RHSVal;
        break;
      case Instruction::SDiv:
        if (!RHSVal.isZero())
          Result = LHSVal.sdiv(RHSVal);
        break;
      case Instruction::UDiv:
        if (!RHSVal.isZero())
          Result = LHSVal.udiv(RHSVal);
        break;
      case Instruction::Shl:
        Result = LHSVal.shl(RHSVal);
        break;
      case Instruction::LShr:
        Result = LHSVal.lshr(RHSVal);
        break;
      case Instruction::AShr:
        Result = LHSVal.ashr(RHSVal);
        break;
      case Instruction::And:
        Result = LHSVal & RHSVal;
        break;
      case Instruction::Or:
        Result = LHSVal | RHSVal;
        break;
      case Instruction::Xor:
        Result = LHSVal ^ RHSVal;
        break;
      default:
        break;
      }

      if (!Result)
        continue;

      ConstantInt *NewVal = ConstantInt::get(BinOp->getContext(), *Result);
      BinOp->replaceAllUsesWith(NewVal);
      ToErase.push_back(BinOp);
      Changed = true;
    }
  }

  for (Instruction *I : ToErase)
    I->eraseFromParent();

  return Changed;
}

